def num_distinct(s: str, t: str) -> int:
    m, n = len(t), len(s)
    if m == 0:
        return 1
    if n < m:
        return 0
    dp = [0] * (m + 1)
    dp[0] = 1
    for c in s:
        for j in reversed(range(m)):
            if c == t[j]:
                dp[j + 1] += dp[j]
    return dp[m]
